if r1@ == SingleDelivery::<Message>::init() && r2@ == SingleDelivery::<Message>::init() {
        assert(r1@.receive_state == Map::<AbstractEndPoint, nat>::empty());
        assert(r1@.send_state == Map::<AbstractEndPoint, AckState<Message>>::empty());
        assert(r2@.receive_state == Map::<AbstractEndPoint, nat>::empty());
        assert(r2@.send_state == Map::<AbstractEndPoint, AckState<Message>>::empty());
