        assert(r2.receive_state.epmap@.map_values(|v: u64| v as nat) == Map::<AbstractEndPoint, nat>::empty());
        assert(r1.receive_state.epmap@.dom() =~= Set::<AbstractEndPoint>::empty());
        assert(r2.receive_state.epmap@.dom() =~= Set::<AbstractEndPoint>::empty());
        assert(r1.receive_state.epmap@ =~= r2.receive_state.epmap@);
        assert(r1.send_state.epmap@.map_values(|v: CAckState| v@) == Map::<AbstractEndPoint, AckState<Message>>::empty());
        assert(r2.send_state.epmap@.map_values(|v: CAckState| v@) == Map::<AbstractEndPoint, AckState<Message>>::empty());
        assert(r1.send_state.epmap@.dom() =~= Set::<AbstractEndPoint>::empty());
        assert(r2.send_state.epmap@.dom() =~= Set::<AbstractEndPoint>::empty());
        assert(r1.send_state.epmap@ =~= r2.send_state.epmap@);
    }
